  gnar: { diff: "EVEN", tone: "#e8b84b", tldr: "Poke mini \u2014 E-knock Mega, win the poke war.", breakdown: "Cannon-Q poke mini Gnar, E-knockback his Mega all-in, and win the poke war.", dos: ["Cannon-Q poke mini Gnar", "E-knockback his Mega all-in", "Win the poke war"], donts: ["Get kited in mini form", "Fight Mega\u2019s all-in raw", "Fight in melee form"], key: { slot: "R", name: "GNAR! (Mega Stun)", cd: "90s", note: "His Mega all-in. E-knock it.", winT: "MINI FORM", winS: "Cannon-Q + hammer him." }, hold: "Hold E to knock back his Mega all-in \u2014 deny his GNAR! engage; poke mini Gnar.", tip: "Cannon-Q poke mini Gnar, E-knockback his Mega all-in, and win the poke war.", win: "Poke mini and knock Mega away." },
